const LowStock = ({ products = [] }: any) => {

  return (

    <div className="table-container">

      <h2>Low Stock ⚠️</h2>

      <table>

        <thead>
          <tr>
            <th>Product</th>
            <th>Stock</th>
          </tr>
        </thead>

        <tbody>

          {products.length > 0 ? (

            products.map((p: any) => (
              <tr key={p.id}>
                <td>{p.name}</td>
                <td>{p.stock}</td>
              </tr>
            ))

          ) : (

            <tr>
              <td colSpan={2} className="empty">
                No low stock products
              </td>
            </tr>

          )}

        </tbody>

      </table>

    </div>

  );

};

export default LowStock;

import { Navigate } from "react-router-dom";

const ProtectedRoute = ({children}:any)=>{

  const token = localStorage.getItem("token");

  if(!token){

    return <Navigate to="/login" />;

  }

  return children;

};

export default ProtectedRoute;

const RecentTransactions = ({ transactions = [] }: any) => {

  return (

    <div className="table-container">

      <h2>Recent Transactions</h2>

      <table>

        <thead>
          <tr>
            <th>ID</th>
            <th>Total</th>
            <th>Date</th>
          </tr>
        </thead>

        <tbody>

          {transactions.length > 0 ? (

            transactions.map((t: any) => (
              <tr key={t.id}>
                <td>{t.id}</td>
                <td>Rp {t.total}</td>
                <td>{t.date}</td>
              </tr>
            ))

          ) : (

            <tr>
              <td colSpan={3} className="empty">
                No transactions yet
              </td>
            </tr>

          )}

        </tbody>

      </table>

    </div>

  );

};

export default RecentTransactions;

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
} from "chart.js";

import { Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const SalesChart = ({ data }: any) => {

  const chartData = {
    labels: data?.labels || [],
    datasets: [
      {
        label: "Sales",
        data: data?.values || [],
        backgroundColor: "#4f46e5",
        borderRadius: 6,
        barThickness: 40
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: {
        display: false
      },
      title: {
        display: true,
        text: "Sales Overview"
      }
    }
  };

  return (
    <div className="chart-card">

      <Bar
        data={chartData}
        options={options}
      />

    </div>
  );
};

export default SalesChart;

const TopProducts = ({ products = [] }: any) => {

  return (

    <div className="table-container">

      <h2>Top Selling Products</h2>

      <table>

        <thead>
          <tr>
            <th>Product</th>
            <th>Sold</th>
          </tr>
        </thead>

        <tbody>

          {products.length > 0 ? (

            products.map((p: any) => (
              <tr key={p.id}>
                <td>{p.name}</td>
                <td>{p.sold}</td>
              </tr>
            ))

          ) : (

            <tr>
              <td colSpan={2} className="empty">
                No top selling products yet
              </td>
            </tr>

          )}

        </tbody>

      </table>

    </div>

  );

};

export default TopProducts;

import { useEffect, useState } from "react";
import api from "../api/axios";

import SalesChart from "../components/SalesChart";
import TopProducts from "../components/TopProducts";
import LowStock from "../components/LowStock";
import RecentTransactions from "../components/RecentTransactions";

import { FaBox, FaShoppingCart, FaMoneyBill } from "react-icons/fa";


/* DUMMY DATA */

const dummyData = {

  totalProducts: 12,
  totalTransactions: 45,
  totalRevenue: 1250000,

  salesChart: {
    labels: ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"],
    values: [200,350,300,500,420,650,700]
  },

  topProducts: [
    { id:1, name:"Indomie", sold:120 },
    { id:2, name:"Teh Botol", sold:95 },
    { id:3, name:"Aqua", sold:80 }
  ],

  lowStock: [
    { id:4, name:"Kopi Kapal Api", stock:3 },
    { id:5, name:"Gula", stock:5 }
  ],

  recentTransactions: [
    { id:101, total:25000, date:"2026-03-31" },
    { id:102, total:18000, date:"2026-03-30" },
    { id:103, total:42000, date:"2026-03-29" }
  ]

};


const Dashboard = () => {

  const [data,setData] = useState<any>({});
  const [loading,setLoading] = useState(true);

  const getDashboard = async () => {

  try {

    const res = await api.get("/dashboard");

    if (!res.data || Object.keys(res.data).length === 0) {
      setData(dummyData);
    } else {
      setData(res.data);
    }

  } catch(err){

    console.log("API error, pakai dummy");

    setData(dummyData);

  } finally {

    setLoading(false);

  }

};

  useEffect(()=>{
    getDashboard();
  },[]);


  const formatRupiah = (number:number)=>{
    return new Intl.NumberFormat("id-ID").format(number || 0);
  };


  if(loading){
    return (
      <div className="content">
        <h2>Loading dashboard...</h2>
      </div>
    );
  }


  return (

    <div className="content">

      <h1>Dashboard</h1>

      {/* STATS */}

      <div className="cards">

        <div className="card">

          <div className="card-header">
            <FaBox className="card-icon"/>
            <h3>Total Products</h3>
          </div>

          <p>{data?.totalProducts || 0}</p>

        </div>


        <div className="card">

          <div className="card-header">
            <FaShoppingCart className="card-icon"/>
            <h3>Total Transactions</h3>
          </div>

          <p>{data?.totalTransactions || 0}</p>

        </div>


        <div className="card">

          <div className="card-header">
            <FaMoneyBill className="card-icon"/>
            <h3>Total Revenue</h3>
          </div>

          <p>Rp {formatRupiah(data?.totalRevenue)}</p>

        </div>

      </div>


      {/* CHART */}

      <div className="chart-container">

        <h2>Sales Overview</h2>

        <SalesChart
          data={data?.salesChart || {labels:[],values:[]}}
        />

      </div>


      {/* GRID TABLE */}

      <div className="grid">

        <TopProducts
          products={data?.topProducts || []}
        />

        <LowStock
          products={data?.lowStock || []}
        />

      </div>


      {/* RECENT TRANSACTIONS */}

      <RecentTransactions
        transactions={data?.recentTransactions || []}
      />

    </div>

  );

};

export default Dashboard;

import { useState, useEffect } from "react";
import toast from "react-hot-toast";
import api from "../api/axios";

const Login = () => {

  const [username,setUsername] = useState("");
  const [password,setPassword] = useState("");
  const [showPassword,setShowPassword] = useState(false);
  const [loading,setLoading] = useState(false);

  // 🔥 Auto redirect kalau sudah login
  useEffect(()=>{

    const token = localStorage.getItem("token");

    if(token){
      window.location.href="/dashboard";
    }

  },[]);

  const handleLogin = async (e:any) => {

    e.preventDefault();

    setLoading(true);

    try {

      const res = await api.post("/auth/login",{
        username,
        password
      });

      console.log("LOGIN SUCCESS:", res.data);

      localStorage.setItem("token", res.data.token);

      window.location.href="/dashboard";

    } catch(err:any){

      console.log("LOGIN ERROR:", err.response?.data);

      toast.error(err.response?.data?.message || "Login gagal");

    } finally {

      setLoading(false);

    }

  };

  return (
    <div className="login-page">

      <form className="login-card" onSubmit={handleLogin}>

        <h1 className="login-title">Warung App</h1>
        <p className="login-subtitle">Welcome back 👋</p>

        {/* USERNAME */}

        <div className="input-group">

          <input
            required
            value={username}
            onChange={(e)=>setUsername(e.target.value)}
          />

          <label>Username</label>

        </div>

        {/* PASSWORD */}

        <div className="input-group password-group">

          <input
            type={showPassword ? "text" : "password"}
            required
            value={password}
            onChange={(e)=>setPassword(e.target.value)}
          />

          <label>Password</label>

          <span
            className="eye-icon"
            onClick={()=>setShowPassword(!showPassword)}
          >
            {showPassword ? "🙈" : "👁"}
          </span>

        </div>

        <button
          className="login-button"
          disabled={loading}
        >
          {loading ? "Loading..." : "Login"}
        </button>

      </form>

    </div>
  );
};

export default Login;

